from flask import Flask, request, redirect, session, url_for
import requests
import urllib.parse

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# OpenID Connect configuration
OIDC_CONFIG = {
    'authorization_endpoint': 'https://your-oidc-provider.com/auth',
    'token_endpoint': 'https://your-oidc-provider.com/token',
    'userinfo_endpoint': 'https://your-oidc-provider.com/userinfo',
    'client_id': 'your-client-id',
    'client_secret': 'your-client-secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid'
}

@app.route('/')
def index():
    return '<a href="/login">Login with SSO</a>'

@app.route('/login')
def login():
    auth_url = f"{OIDC_CONFIG['authorization_endpoint']}?response_type=id_token&client_id={OIDC_CONFIG['client_id']}&redirect_uri={OIDC_CONFIG['redirect_uri']}&scope={OIDC_CONFIG['scope']}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    # Extract id_token from the callback
    id_token = request.args.get('id_token')
    
    if not id_token:
        return "Authentication failed", 400
    
    # Store the token in session
    session['id_token'] = id_token
    
    # Redirect to admin dashboard
    return redirect(url_for('admin_dashboard'))

@app.route('/admin')
def admin_dashboard():
    if 'id_token' not in session:
        return redirect(url_for('login'))
    
    # Here you would typically validate the id_token
    # and extract user information
    return f"Welcome to Admin Dashboard! Token: {session['id_token'][:20]}..."

if __name__ == '__main__':
    app.run(debug=True)